#[cfg(test)]
lazy_static::lazy_static! {
  // simulate the global C variables that point to the microkit shared memory regions.  In a full
  // microkit system we would be able to mutate the shared memory for out ports since they're r/w,
  // but we couldn't do that for in ports since they are read-only
  pub static ref OUT_write_port: Mutex<Option<vest_1prod_1cons::ArrayOfByte>> = Mutex::new(None);
}

#[cfg(test)]
pub fn initialize_test_globals() {
  unsafe {
    *OUT_write_port.lock().unwrap_or_else(|e| e.into_inner()) = None;
  }
}

#[cfg(test)]
pub fn put_write_port(value: *mut vest_1prod_1cons::ArrayOfByte) -> bool
{
  unsafe {
    *OUT_write_port.lock().unwrap_or_else(|e| e.into_inner()) = Some(*value);
    return true;
  }
}
